class SettingsActivity extends AppCompatActivity {

    private static final String PREFS_NAME = "auth_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_BIOMETRIC_AUTHENTICATED = "biometric_authenticated";

    private SharedPreferences prefs;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_settings);

        prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);

        Button enableBiometricButton = findViewById(R.id.btnEnableBiometric);
        Button disableBiometricButton = findViewById(R.id.btnDisableBiometric);

        enableBiometricButton.setOnClickListener(v -> enableBiometricLogin());
        disableBiometricButton.setOnClickListener(v -> disableBiometricLogin());
    }

    private void enableBiometricLogin() {
        if (!isBiometricAvailable()) {
            Toast.makeText(this, "Biometric authentication not available", Toast.LENGTH_SHORT).show();
            return;
        }

        prefs.edit()
                .putBoolean(KEY_BIOMETRIC_ENABLED, true)
                .putBoolean(KEY_BIOMETRIC_AUTHENTICATED, false)
                .apply();

        Toast.makeText(this, "Biometric login enabled", Toast.LENGTH_SHORT).show();
    }

    private void disableBiometricLogin() {
        prefs.edit()
                .putBoolean(KEY_BIOMETRIC_ENABLED, false)
                .putBoolean(KEY_BIOMETRIC_AUTHENTICATED, false)
                .apply();

        Toast.makeText(this, "Biometric login disabled", Toast.LENGTH_SHORT).show();
    }

    private boolean isBiometricAvailable() {
        androidx.biometric.BiometricManager biometricManager = androidx.biometric.BiometricManager.from(this);
        int result = biometricManager.canAuthenticate(androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return result == androidx.biometric.BiometricManager.BIOMETRIC_SUCCESS;
    }
}

